class Solution {
public:
    int countDigitOne(int n) {
        long long d = 1;
        int res = 0;
        while (d <= n) {
            long long high = n / (d * 10);
            int current = (n / d) % 10;
            long long low = n % d;
            res += high * d;
            if (current > 1) {
                res += d;
            } else if (current == 1) {
                res += low + 1;
            }
            d *= 10;
        }
        return res;
    }
};

